    [Fact]
    public void BogConnection_Query_SetCastTypedProperties_PersistsNumericValues()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Metric", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "small", BogDb.Core.Common.LogicalTypeID.INT16 },
            { "qty", BogDb.Core.Common.LogicalTypeID.INT32 },
            { "ratio", BogDb.Core.Common.LogicalTypeID.FLOAT },
            { "exact", BogDb.Core.Common.LogicalTypeID.DOUBLE },
            { "active", BogDb.Core.Common.LogicalTypeID.BOOL },
            { "label", BogDb.Core.Common.LogicalTypeID.STRING },
        });
        connection.Commit();

        Assert.True(connection.Query("CREATE (:Metric {id:1, active:true, label:'alpha'})").IsSuccess);
        Assert.True(connection.Query("MATCH (m:Metric {id:1}) SET m.small = CAST(7 AS INT16), m.qty = CAST(100 AS INT32), m.ratio = CAST(1.5 AS FLOAT), m.exact = CAST(1.125 AS DOUBLE)").IsSuccess);

        var scan = connection.Query("MATCH (m:Metric {id:1}) RETURN m.small, m.qty, m.ratio, m.exact");
        Assert.True(scan.IsSuccess, scan.ErrorMessage);
        Assert.True(scan.HasNext());

        var row = scan.GetNext();
        Assert.Equal(7L, row.GetInt64(0));
        Assert.Equal(100L, row.GetInt64(1));
        Assert.Equal(1.5, row.GetDouble(2), 5);
        Assert.Equal(1.125, row.GetDouble(3), 5);

        var filter = connection.Query("MATCH (m:Metric) WHERE m.ratio > 1.0 RETURN m.id");
        Assert.True(filter.IsSuccess, filter.ErrorMessage);
        Assert.True(filter.HasNext());
        Assert.Equal(1L, filter.GetNext().GetInt64(0));
    }

