    [Fact]
    public void BogConnection_CopyFrom_ExecutesSuccessfullyAndPopulatesNodeTable()
    {
        // Assemble 
        var tempFile = System.IO.Path.GetTempFileName().Replace("\\", "/");
        System.IO.File.WriteAllText(tempFile, "id\n70\n80\n90");

        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        var cypherString = $"COPY Person FROM '{tempFile}'";

        // Pre-create the local node table to intercept the insert.
        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID> {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.Commit();

        // Act
        var result = connection.Query(cypherString);

        // Assert
        Assert.True(result.IsSuccess);
        
        // Storage assertions for Phase 8 Bulk insertions:
        var props70 = connection.ReadNode("Person", 70L);
        Assert.NotNull(props70);
        Assert.Equal(70L, props70["id"]);

        var props90 = connection.ReadNode("Person", 90L);
        Assert.NotNull(props90);
        Assert.Equal(90L, props90["id"]);

        // Cleanup
        System.IO.File.Delete(tempFile);
    }

    [Fact]
    public void BogConnection_Query_OrderBy_ReturnsSortedResults()
    {
        var dbPath = "e2e_test_db_orderby";
        if (System.IO.Directory.Exists(dbPath)) System.IO.Directory.Delete(dbPath, true);

        using var database = BogDatabase.Open(dbPath);
        using var connection = new BogConnection(database);
        connection.BeginWriteTransaction();

        // Schema
        var schema = new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            {"name", BogDb.Core.Common.LogicalTypeID.STRING},
            {"age", BogDb.Core.Common.LogicalTypeID.INT64}
        };
        connection.EnsureNodeTable("Person", schema);

        // Insert nodes (unsorted)
        connection.UpsertNode("Person", 3L, new System.Collections.Generic.Dictionary<string, object> {{"name", "Charlie"}, {"age", 30L}});
        connection.UpsertNode("Person", 1L, new System.Collections.Generic.Dictionary<string, object> {{"name", "Alice"}, {"age", 25L}});
        connection.UpsertNode("Person", 2L, new System.Collections.Generic.Dictionary<string, object> {{"name", "Bob"}, {"age", 25L}});
        connection.UpsertNode("Person", 4L, new System.Collections.Generic.Dictionary<string, object> {{"name", "David"}, {"age", 40L}});
        connection.Commit();

        // 1. ORDER BY Simple Ascending
        var result1 = connection.Query("MATCH (p:Person) RETURN p.name AS name, p.age AS age ORDER BY p.age;");
        Assert.True(result1.IsSuccess);
        Assert.Equal(4UL, result1.GetNumTuples());
        Assert.Equal(25L, result1.GetNext().GetInt64(1)); // Alice or Bob
        Assert.Equal(25L, result1.GetNext().GetInt64(1)); // Alice or Bob
        Assert.Equal(30L, result1.GetNext().GetInt64(1));
        Assert.Equal(40L, result1.GetNext().GetInt64(1));

        // 2. ORDER BY Multiple properties (age ASC, name DESC)
        var result2 = connection.Query("MATCH (p:Person) RETURN p.name AS name ORDER BY p.age, p.name DESC;");
        Assert.True(result2.IsSuccess);
        Assert.Equal(4UL, result2.GetNumTuples());
        Assert.Equal("Bob", result2.GetNext().GetString(0)); // Bob (25) comes before Alice (25) because DESC
        Assert.Equal("Alice", result2.GetNext().GetString(0));
        Assert.Equal("Charlie", result2.GetNext().GetString(0));
        Assert.Equal("David", result2.GetNext().GetString(0));
    }

    [Fact]
    public void BogConnection_Query_OrderBy_ExternalChunkedSort_ReturnsSortedResults()
    {
        var originalChunkLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit;
        var originalChunkByteLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = 2;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = null;

        try
        {
            using var database = BogDatabase.Open(":memory:");
            using var connection = new BogConnection(database);

            var result = connection.Query(
                "UNWIND [9, 3, 7, 1, 8, 2, 6, 4, 5] AS x " +
                "RETURN x ORDER BY x");

            Assert.True(result.IsSuccess, result.ErrorMessage);
            Assert.Equal(9UL, result.GetNumTuples());

            for (var expected = 1L; expected <= 9L; expected++)
            {
                Assert.True(result.HasNext());
                Assert.Equal(expected, result.GetNext().GetInt64(0));
            }
        }
        finally
        {
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = originalChunkLimit;
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = originalChunkByteLimit;
        }
    }

    [Fact]
    public void BogConnection_Query_WithOrderBy_ExternalChunkedSort_PreservesBindingsForDownstreamClauses()
    {
        var originalChunkLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit;
        var originalChunkByteLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = 2;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = null;

        try
        {
            using var database = BogDatabase.Open(":memory:");
            using var connection = new BogConnection(database);

            var result = connection.Query(
                "UNWIND [9, 3, 7, 1, 8, 2] AS x " +
                "WITH x ORDER BY x " +
                "RETURN x, x * 10 AS y");

            Assert.True(result.IsSuccess, result.ErrorMessage);
            Assert.Equal(6UL, result.GetNumTuples());

            var expectedValues = new long[] { 1L, 2L, 3L, 7L, 8L, 9L };
            foreach (var expected in expectedValues)
            {
                Assert.True(result.HasNext());
                var row = result.GetNext();
                Assert.Equal(expected, row.GetInt64(0));
                Assert.Equal(expected * 10L, row.GetInt64(1));
            }
        }
        finally
        {
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = originalChunkLimit;
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = originalChunkByteLimit;
        }
    }

