    {
        var originalChunkLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit;
        var originalChunkByteLimit = BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = int.MaxValue;
        BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = 512;

        try
        {
            using var database = BogDatabase.Open(":memory:");
            using var connection = new BogConnection(database);

            var a = new string('a', 320);
            var b = new string('b', 320);
            var c = new string('c', 320);

            var result = connection.Query(
                $"UNWIND ['{c}', '{a}', '{b}'] AS x " +
                "RETURN x ORDER BY x");

            Assert.True(result.IsSuccess, result.ErrorMessage);
            Assert.Equal(3UL, result.GetNumTuples());
            Assert.Equal(a, result.GetNext().GetString(0));
            Assert.Equal(b, result.GetNext().GetString(0));
            Assert.Equal(c, result.GetNext().GetString(0));
        }
        finally
        {
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkRowLimit = originalChunkLimit;
            BogDb.Core.Processor.Operator.OrderBy.OrderBy.ChunkByteLimitOverride = originalChunkByteLimit;
        }
    }

    [Fact]
    public void BogConnection_Query_SkipAndLimit_FiltersResultSize()
    {
        var dbPath = "e2e_test_db_skiplimit";
        if (System.IO.Directory.Exists(dbPath)) System.IO.Directory.Delete(dbPath, true);

        using var database = BogDatabase.Open(dbPath);
        using var connection = new BogConnection(database);
        connection.BeginWriteTransaction();

        var schema = new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            {"val", BogDb.Core.Common.LogicalTypeID.INT64}
        };
        connection.EnsureNodeTable("Num", schema);

        for (long i = 0; i < 10; i++)
        {
            connection.UpsertNode("Num", i, new System.Collections.Generic.Dictionary<string, object> {{"val", i}});
        }
        connection.Commit();

        // Test SKIP 5
        var res1 = connection.Query("MATCH (n:Num) RETURN n.val AS val ORDER BY n.val SKIP 5;");
        Assert.Equal(5UL, res1.GetNumTuples());
        Assert.Equal(5L, res1.GetNext().GetInt64(0));

        // Test LIMIT 3
        var res2 = connection.Query("MATCH (n:Num) RETURN n.val AS val ORDER BY n.val LIMIT 3;");
        Assert.Equal(3UL, res2.GetNumTuples());
        Assert.Equal(0L, res2.GetNext().GetInt64(0));
        res2.GetNext(); // dummy skip index 1
        Assert.Equal(2L, res2.GetNext().GetInt64(0));

        // Test SKIP 3 LIMIT 2
        var res3 = connection.Query("MATCH (n:Num) RETURN n.val AS val ORDER BY n.val SKIP 3 LIMIT 2;");
        Assert.Equal(2UL, res3.GetNumTuples());
        Assert.Equal(3L, res3.GetNext().GetInt64(0));
        Assert.Equal(4L, res3.GetNext().GetInt64(0));

        // Test SKIP evaluates expressions (e.g. 1 + 2)
        var res4 = connection.Query("MATCH (n:Num) RETURN n.val AS val ORDER BY n.val SKIP 1 + 2 LIMIT 1 + 1;");
        Assert.Equal(2UL, res4.GetNumTuples());
        Assert.Equal(3L, res4.GetNext().GetInt64(0));
        Assert.Equal(4L, res4.GetNext().GetInt64(0));
    }

