        });
        connection.EnsureRelTable("EDGE", "Node", "Node", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "weight", BogDb.Core.Common.LogicalTypeID.INT64 }
        });

        connection.UpsertNode("Node", 1L, new System.Collections.Generic.Dictionary<string, object> { { "id", 1L }, { "label", "A" } });
