        connection.UpsertNode("Node", 3L, new System.Collections.Generic.Dictionary<string, object> { { "id", 3L }, { "label", "C" } });
        connection.UpsertNode("Node", 4L, new System.Collections.Generic.Dictionary<string, object> { { "id", 4L }, { "label", "D" } });
        connection.UpsertNode("Node", 5L, new System.Collections.Generic.Dictionary<string, object> { { "id", 5L }, { "label", "E" } });

        connection.UpsertRelationship("EDGE", 1L, 2L, new System.Collections.Generic.Dictionary<string, object> { { "weight", 1L } });
        connection.UpsertRelationship("EDGE", 2L, 3L, new System.Collections.Generic.Dictionary<string, object> { { "weight", 2L } });
        connection.UpsertRelationship("EDGE", 3L, 4L, new System.Collections.Generic.Dictionary<string, object> { { "weight", 3L } });
        connection.UpsertRelationship("EDGE", 4L, 5L, new System.Collections.Generic.Dictionary<string, object> { { "weight", 4L } });
        connection.UpsertRelationship("EDGE", 1L, 3L, new System.Collections.Generic.Dictionary<string, object> { { "weight", 5L } });
        connection.Commit();

        var distinctResult = connection.Query(
            "MATCH (a:Node)-[:EDGE*1..2]->(b:Node) WHERE a.id = 1 RETURN DISTINCT b.id ORDER BY b.id");

