            "MATCH (a:Node)-[:EDGE*1..4]->(b:Node) WHERE a.id = 1 RETURN COUNT(DISTINCT b.id) AS cnt");

        Assert.True(countDistinctResult.IsSuccess, countDistinctResult.ErrorMessage);
        Assert.Equal(1UL, countDistinctResult.GetNumTuples());
        Assert.Equal(4L, countDistinctResult.GetNext().GetInt64(0));
    }

