        Assert.True(row.GetBoolean(3));
        Assert.True(row.GetBoolean(4));
        Assert.False(row.GetBoolean(5));
        Assert.True(row.GetBoolean(6));
        Assert.False(row.GetBoolean(7));
    }

    [Fact]
    public void BogConnection_Query_Parameters_BindAtRuntime_ForScalarsAndCollections()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "name", BogDb.Core.Common.LogicalTypeID.STRING },
            { "age", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.UpsertNode("Person", 1L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Alice" }, { "age", 25L } });
        connection.UpsertNode("Person", 2L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Bob" }, { "age", 40L } });
        connection.Commit();

        var filter = connection.Query(
            "MATCH (p:Person) WHERE p.age >= $minAge RETURN p.name AS name ORDER BY name",
            new System.Collections.Generic.Dictionary<string, object?>
            {
                ["minAge"] = 30L
            });

        Assert.True(filter.IsSuccess, filter.ErrorMessage);
        Assert.Equal(1UL, filter.GetNumTuples());
        Assert.Equal("Bob", filter.GetNext().GetString(0));

        var projection = connection.Query(
            "RETURN $name AS name, ALL(x IN $scores WHERE x >= $threshold) AS all_above",
            new System.Collections.Generic.Dictionary<string, object?>
            {
                ["$name"] = "alpha",
                ["scores"] = new object?[] { 7L, 8L, 9L },
