        connection.UpsertNode("Person", 2L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Bob" } });
        connection.UpsertNode("Person", 3L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Carol" } });
        connection.UpsertNode("Company", 10L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Acme" } });
        connection.UpsertNode("Company", 20L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Beta" } });
        connection.UpsertNode("Company", 30L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Core" } });
        connection.UpsertRelationship("WORKS_AT", 1L, 10L, new System.Collections.Generic.Dictionary<string, object>());
        connection.UpsertRelationship("WORKS_AT", 1L, 20L, new System.Collections.Generic.Dictionary<string, object>());
        connection.UpsertRelationship("WORKS_AT", 3L, 30L, new System.Collections.Generic.Dictionary<string, object>());
        connection.Commit();

        var result = connection.Query(
            "MATCH (p:Person) OPTIONAL MATCH (p)-[:WORKS_AT]->(c:Company) RETURN p.name, c.name");

        Assert.True(result.IsSuccess, result.ErrorMessage);
        Assert.Equal(4UL, result.GetNumTuples());

        var rows = new System.Collections.Generic.List<string>();
