        Assert.Equal("Dave", row2.GetString(2));

        var row3 = result.GetNext();
        Assert.Equal("Ann", row3.GetString(0));
        Assert.Equal("Bob", row3.GetString(1));
        Assert.Equal("Carol", row3.GetString(2));

        var row4 = result.GetNext();
        Assert.Equal("Ann", row4.GetString(0));
        Assert.Equal("Bob", row4.GetString(1));
        Assert.Equal("Dave", row4.GetString(2));
    }

