    [Fact]
    public void BogConnection_Query_MergeSingleNode_Fails_WhenExplicitPrimaryKeyExistsWithDifferentProperties()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "age", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.UpsertNode("Person", 1L, new System.Collections.Generic.Dictionary<string, object>
        {
            { "age", 35L }
        });
        connection.Commit();

        var merge = connection.Query("MERGE (:Person {id:1, age:10})");

        Assert.False(merge.IsSuccess);
        Assert.Contains(
            "Found duplicated primary key value 1, which violates the uniqueness constraint of the primary key column.",
            merge.ErrorMessage);

        var verify = connection.Query("MATCH (p:Person {id:1}) RETURN p.age");
        Assert.True(verify.IsSuccess, verify.ErrorMessage);
        Assert.Equal(1UL, verify.GetNumTuples());
        Assert.Equal(35L, verify.GetNext().GetInt64(0));
    }

    [Fact]
    public void BogConnection_Query_MergeSingleRelationship_BetweenBoundEndpoints_CreatesThenMatches_AndHonorsMergeActions()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "name", BogDb.Core.Common.LogicalTypeID.STRING }
        });
        connection.EnsureNodeTable("Company", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "name", BogDb.Core.Common.LogicalTypeID.STRING }
        });
        connection.EnsureRelTable("WORKS_AT", "Person", "Company", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "since", BogDb.Core.Common.LogicalTypeID.INT64 },
            { "note", BogDb.Core.Common.LogicalTypeID.STRING }
        });
        connection.UpsertNode("Person", 1L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Alice" } });
        connection.UpsertNode("Company", 10L, new System.Collections.Generic.Dictionary<string, object> { { "name", "Acme" } });
        connection.Commit();

        var createResult = connection.Query(
            "MATCH (p:Person {id:1}), (c:Company {id:10}) " +
            "MERGE (p)-[r:WORKS_AT {since:2020}]->(c) " +
            "ON CREATE SET r.note = 'created' " +
            "ON MATCH SET r.note = 'matched' " +
            "RETURN r.since, r.note");

        Assert.True(createResult.IsSuccess, createResult.ErrorMessage);
        Assert.Equal(1UL, createResult.GetNumTuples());
        var createdRow = createResult.GetNext();
        Assert.Equal(2020L, createdRow.GetInt64(0));
        Assert.Equal("created", createdRow.GetString(1));

        var matchResult = connection.Query(
            "MATCH (p:Person {id:1}), (c:Company {id:10}) " +
            "MERGE (p)-[r:WORKS_AT {since:2020}]->(c) " +
            "ON CREATE SET r.note = 'created' " +
            "ON MATCH SET r.note = 'matched' " +
            "RETURN r.since, r.note");

        Assert.True(matchResult.IsSuccess, matchResult.ErrorMessage);
        Assert.Equal(1UL, matchResult.GetNumTuples());
        var matchedRow = matchResult.GetNext();
        Assert.Equal(2020L, matchedRow.GetInt64(0));
        Assert.Equal("matched", matchedRow.GetString(1));

        var verify = connection.Query(
            "MATCH (:Person {id:1})-[r:WORKS_AT]->(:Company {id:10}) RETURN r.note");

        Assert.True(verify.IsSuccess, verify.ErrorMessage);
        Assert.Equal(1UL, verify.GetNumTuples());
        Assert.Equal("matched", verify.GetNext().GetString(0));
    }

