    [Fact]
    public void BogConnection_Query_MergeSingleRelationship_CanCreateParallelEdges_ForSameEndpoints()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.EnsureRelTable("LIKES", "Person", "Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.EnsureRelTable("STUDY", "Person", "Person", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "length", BogDb.Core.Common.LogicalTypeID.STRING }
        });
        connection.UpsertNode("Person", 0L, new System.Collections.Generic.Dictionary<string, object>());
        connection.UpsertNode("Person", 3L, new System.Collections.Generic.Dictionary<string, object>());
        connection.Commit();

        var first = connection.Query(
            "MATCH (p:Person {id:0}), (p1:Person {id:3}) " +
            "MERGE (p)-[e:LIKES {id:1}]->(p1)");
        Assert.True(first.IsSuccess, first.ErrorMessage);

        var second = connection.Query(
            "MATCH (p:Person {id:0}), (p1:Person {id:3}) " +
            "MERGE (p)-[e:LIKES {id:2}]->(p1)");
        Assert.True(second.IsSuccess, second.ErrorMessage);

        var third = connection.Query(
            "MATCH (p:Person {id:0}), (p1:Person {id:3}) " +
            "MERGE (p)-[e:LIKES {id:1}]->(p1)");
        Assert.True(third.IsSuccess, third.ErrorMessage);

        var likes = connection.Query(
            "MATCH (:Person {id:0})-[e:LIKES]->(:Person {id:3}) RETURN e.id ORDER BY e.id");
        Assert.True(likes.IsSuccess, likes.ErrorMessage);
        Assert.Equal(2UL, likes.GetNumTuples());
        Assert.True(likes.HasNext());
        Assert.Equal(1L, likes.GetNext().GetInt64(0));
        Assert.True(likes.HasNext());
        Assert.Equal(2L, likes.GetNext().GetInt64(0));
    }

    [Fact]
    public void BogConnection_Query_WithAggregate_CanReuseComputedStringAlias_FromWithScope()
    {
        using var database = BogDatabase.Open(":memory:");
        using var connection = new BogConnection(database);

        connection.BeginWriteTransaction();
        connection.EnsureNodeTable("Step", new System.Collections.Generic.Dictionary<string, BogDb.Core.Common.LogicalTypeID>
        {
            { "id", BogDb.Core.Common.LogicalTypeID.STRING },
            { "keyword", BogDb.Core.Common.LogicalTypeID.STRING },
            { "name", BogDb.Core.Common.LogicalTypeID.STRING },
            { "duration_ms", BogDb.Core.Common.LogicalTypeID.INT64 }
        });
        connection.UpsertNode("Step", "s1", new System.Collections.Generic.Dictionary<string, object>
        {
            { "keyword", "Given " },
            { "name", "a cucumber" },
            { "duration_ms", 12L }
        });
        connection.Commit();

        var result = connection.Query(
            "MATCH (s:Step) " +
            "WITH (s.keyword + s.name) AS step, avg(s.duration_ms) AS avg_ms, count(s) AS appearances " +
            "RETURN step, avg_ms, appearances");

        Assert.True(result.IsSuccess, result.ErrorMessage);
        Assert.Equal(1UL, result.GetNumTuples());

        var row = result.GetNext();
        Assert.Equal("Given a cucumber", row.GetString(0));
        Assert.Equal(12.0, row.GetDouble(1), 5);
        Assert.Equal(1L, row.GetInt64(2));
    }
